// HasProcurementReviews applies the HasEdge predicate on the "procurement_reviews" edge.
func HasProcurementReviews() predicate.ProcurementExpert {
	return predicate.ProcurementExpert(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2M, true, ProcurementReviewsTable, ProcurementReviewsPrimaryKey...),
		)
		schemaConfig := internal.SchemaConfigFromContext(s.Context())
		step.To.Schema = schemaConfig.ProcurementReview
		step.Edge.Schema = schemaConfig.ProcurementReviewProcurementExperts
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasProcurementReviewsWith applies the HasEdge predicate on the "procurement_reviews" edge with a given conditions (other predicates).
func HasProcurementReviewsWith(preds ...predicate.ProcurementReview) predicate.ProcurementExpert {
	return predicate.ProcurementExpert(func(s *sql.Selector) {
		step := newProcurementReviewsStep()
		schemaConfig := internal.SchemaConfigFromContext(s.Context())
		step.To.Schema = schemaConfig.ProcurementReview
		step.Edge.Schema = schemaConfig.ProcurementReviewProcurementExperts
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

